import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { fetchTables, addTable, deleteTable } from '../features/tables/tablesSlice';

export default function AdminPage() {
  const dispatch = useDispatch();
  const { all: tables } = useSelector(s => s.tables);
  const [form, setForm] = useState({ number: '', capacity: '', location: 'main' });
  const [msg, setMsg] = useState('');

  useEffect(() => { dispatch(fetchTables()); }, []);

  const handleAdd = async e => {
    e.preventDefault();
    const res = await dispatch(addTable(form));
    if (!res.error) { setMsg('Table added'); setForm({ number: '', capacity: '', location: 'main' }); }
    else setMsg(res.payload);
  };

  return (
    <div style={styles.wrap}>
      <h2>Admin — Table Management</h2>
      {msg && <p style={{ color: msg.includes('added') ? 'green' : 'red' }}>{msg}</p>}

      <form onSubmit={handleAdd} style={styles.form}>
        <input style={styles.input} type="number" placeholder="Table #" value={form.number}
          onChange={e => setForm({ ...form, number: parseInt(e.target.value) })} required />
        <input style={styles.input} type="number" placeholder="Capacity" value={form.capacity}
          onChange={e => setForm({ ...form, capacity: parseInt(e.target.value) })} required />
        <select style={styles.input} value={form.location}
          onChange={e => setForm({ ...form, location: e.target.value })}>
          <option value="main">Main</option>
          <option value="window">Window</option>
          <option value="private">Private</option>
          <option value="outdoor">Outdoor</option>
        </select>
        <button style={styles.btn} type="submit">Add Table</button>
      </form>

      <table style={styles.table}>
        <thead>
          <tr>
            {['#', 'Capacity', 'Location', 'Actions'].map(h => <th key={h} style={styles.th}>{h}</th>)}
          </tr>
        </thead>
        <tbody>
          {tables.map(t => (
            <tr key={t.id} style={styles.tr}>
              <td style={styles.td}>{t.number}</td>
              <td style={styles.td}>{t.capacity}</td>
              <td style={styles.td}>{t.location}</td>
              <td style={styles.td}>
                <button style={styles.delBtn} onClick={() => dispatch(deleteTable(t.id))}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

const styles = {
  wrap:   { maxWidth: 800, margin: '32px auto', padding: '0 16px' },
  form:   { display: 'flex', gap: 12, marginBottom: 24, flexWrap: 'wrap' },
  input:  { padding: '8px', border: '1px solid #ddd', borderRadius: 4, fontSize: '0.95rem', flex: 1, minWidth: 120 },
  btn:    { padding: '8px 18px', background: '#e94560', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' },
  table:  { width: '100%', borderCollapse: 'collapse', background: '#fff', borderRadius: 8, boxShadow: '0 1px 6px rgba(0,0,0,0.08)' },
  th:     { padding: '12px 16px', background: '#1a1a2e', color: '#fff', textAlign: 'left' },
  tr:     { borderBottom: '1px solid #f0f0f0' },
  td:     { padding: '10px 16px' },
  delBtn: { padding: '5px 12px', background: '#e74c3c', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' },
};
